```class Solution {
    public String reverseStr(String s, int k) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < s.length(); i += 2 * k) {
            sb.append(new StringBuilder(s.substring(i, Math.min(i + k, s.length()))).reverse().toString());
            if (i + k < s.length()) {
                sb.append(s.substring(i + k));
            }
        }
        return sb.toString();
    }
}```
